diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 842881156dc6..cf110ca643c3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3567,6 +3567,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
           }
       }
     }
+
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
@@ -3760,6 +3761,31 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         if (Instruction *R = FoldOpIntoSelect(*II, Sel))
           return R;

+  if (IID == Intrinsic::umax) {
+    auto FoldUMaxShlAdd = [&](Value *ShlOp, Value *AddOp) -> Instruction * {
+      Value *X;
+      if (!match(ShlOp, m_NUWShl(m_Value(X), m_One())))
+        return nullptr;
+      if (!match(AddOp, m_Add(m_Specific(X), m_One())))
+        return nullptr;
+      auto *ITy = dyn_cast<IntegerType>(X->getType());
+      if (!ITy || II->getType() != X->getType())
+        return nullptr;
+
+      Value *IsZero = Builder.CreateICmpEQ(X, ConstantInt::get(ITy, 0));
+      Value *Res =
+          Builder.CreateSelect(IsZero, ConstantInt::get(ITy, 1), ShlOp);
+      return replaceInstUsesWith(CI, Res);
+    };
+
+    if (Instruction *R =
+            FoldUMaxShlAdd(II->getArgOperand(0), II->getArgOperand(1)))
+      return R;
+    if (Instruction *R =
+            FoldUMaxShlAdd(II->getArgOperand(1), II->getArgOperand(0)))
+      return R;
+  }
+
   if (Instruction *Shuf = foldShuffledIntrinsicOperands(II, Builder))
     return Shuf;

@@ -3768,6 +3794,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

